def faithfulness_evaluator(run, example):
    """Score: is the answer grounded in the retrieved context?"""
    output  = OpenAI()
    verdict = output.chat.completions.create(
        model='gpt-4o',
        messages=[{'role': 'user', 'content': f"""
            Context: {run.inputs.get('context','')}
            Answer:  {run.outputs.get('answer','')}
            Is the answer fully supported by the context? Reply YES or NO.
        """}]
    ).choices[0].message.content.strip()
    return {'key': 'faithfulness', 'score': 1 if verdict == 'YES' else 0}

